import React, { useRef, useEffect, useState } from 'react';
import { Mic, MicOff, Sparkles, Image as ImageIcon } from 'lucide-react';
import { JournalEntry, TimestampBlock } from '../types';
import { transcribeAudio } from '../services/geminiService';

interface DailyEditorProps {
  entry: JournalEntry;
  updateEntry: (id: string, blocks: TimestampBlock[]) => void;
  onGenerateAI: (text: string) => void;
}

const DailyEditor: React.FC<DailyEditorProps> = ({ entry, updateEntry, onGenerateAI }) => {
  const [isRecording, setIsRecording] = useState(false);
  const [recordingStatus, setRecordingStatus] = useState<string>('');
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<BlobPart[]>([]);

  // Focus the last block on mount if empty
  useEffect(() => {
    if (entry.blocks.length === 0) {
      addBlock();
    }
  }, []);

  const addBlock = (text: string = '', timeOverride?: string) => {
    const time = timeOverride || new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    const newBlock: TimestampBlock = {
      id: Date.now().toString() + Math.random().toString(),
      time,
      text
    };
    updateEntry(entry.id, [...entry.blocks, newBlock]);
  };

  const updateBlockText = (blockId: string, text: string) => {
    const newBlocks = entry.blocks.map(b => 
      b.id === blockId ? { ...b, text } : b
    );
    updateEntry(entry.id, newBlocks);
  };

  const handleKeyDown = (e: React.KeyboardEvent, index: number) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      addBlock();
      // Wait a tick for render then focus next input
      setTimeout(() => {
        const inputs = document.querySelectorAll('.journal-textarea');
        if (inputs[index + 1]) {
          (inputs[index + 1] as HTMLTextAreaElement).focus();
        }
      }, 0);
    } else if (e.key === 'Backspace' && entry.blocks[index].text === '' && index > 0) {
      e.preventDefault();
      const newBlocks = entry.blocks.filter((_, i) => i !== index);
      updateEntry(entry.id, newBlocks);
      setTimeout(() => {
        const inputs = document.querySelectorAll('.journal-textarea');
        if (inputs[index - 1]) {
          (inputs[index - 1] as HTMLTextAreaElement).focus();
        }
      }, 0);
    }
  };

  // Voice Recording Logic
  const toggleRecording = async () => {
    if (isRecording) {
      stopRecording();
    } else {
      startRecording();
    }
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      chunksRef.current = [];

      mediaRecorder.ondataavailable = (e) => {
        if (e.data.size > 0) chunksRef.current.push(e.data);
      };

      mediaRecorder.onstop = async () => {
        setRecordingStatus('Transcribing...');
        const blob = new Blob(chunksRef.current, { type: 'audio/webm' });
        try {
          const text = await transcribeAudio(blob);
          addBlock(text);
          setRecordingStatus('');
        } catch (error) {
          setRecordingStatus('Error transcribing');
          console.error(error);
        }
        stream.getTracks().forEach(track => track.stop());
      };

      mediaRecorder.start();
      setIsRecording(true);
    } catch (err) {
      console.error("Mic error:", err);
      setRecordingStatus('Mic Access Denied');
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
    }
  };

  const autoResizeTextarea = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    e.target.style.height = 'auto';
    e.target.style.height = e.target.scrollHeight + 'px';
  };

  return (
    <div className="w-full max-w-4xl mx-auto pb-40">
      {/* Header */}
      <div className="mb-8 border-b border-journal-600 pb-4">
        <h1 className="text-3xl font-bold text-white mb-1">{entry.formattedDate}</h1>
        <input 
          type="text" 
          value={entry.title}
          onChange={(e) => {
            // Update title logic would go here in a real app store
          }}
          placeholder="Give today a title..."
          className="bg-transparent text-journal-700 text-lg w-full focus:outline-none focus:text-journal-accent transition-colors"
        />
      </div>

      {/* Toolbar */}
      <div className="sticky top-20 z-30 flex justify-end mb-4 space-x-2">
         <button 
           onClick={() => onGenerateAI(entry.blocks.map(b => b.text).join('\n'))}
           className="p-2 bg-journal-800 rounded-full text-purple-400 hover:bg-purple-900/30 transition-colors"
           title="AI Insights"
         >
           <Sparkles size={20} />
         </button>
         <button className="p-2 bg-journal-800 rounded-full text-gray-400 hover:text-white transition-colors">
           <ImageIcon size={20} />
         </button>
         <button 
           onClick={toggleRecording}
           className={`p-2 rounded-full transition-colors flex items-center space-x-2 ${isRecording ? 'bg-red-500/20 text-red-500' : 'bg-journal-800 text-gray-400 hover:text-white'}`}
         >
           {isRecording ? <MicOff size={20} /> : <Mic size={20} />}
           {isRecording && <span className="text-xs font-bold animate-pulse">REC</span>}
         </button>
      </div>

      {recordingStatus && (
        <div className="text-center text-xs text-journal-accent mb-4 animate-pulse">
          {recordingStatus}
        </div>
      )}

      {/* Editor Blocks */}
      <div className="space-y-1">
        {entry.blocks.map((block, index) => (
          <div key={block.id} className="group flex items-start -ml-16">
            {/* Timestamp Margin */}
            <div className="w-14 text-right pr-3 pt-1.5 text-xs text-gray-500 select-none font-mono opacity-50 group-focus-within:opacity-100 group-hover:opacity-100 transition-opacity">
              {block.time}
            </div>

            {/* Divider Line */}
            <div className="w-px bg-journal-600 self-stretch mr-4 relative">
               <div className="absolute top-2.5 -left-[3px] w-1.5 h-1.5 rounded-full bg-journal-600 group-focus-within:bg-journal-accent transition-colors"></div>
            </div>

            {/* Input Area */}
            <textarea
              className="journal-textarea flex-1 bg-transparent text-gray-200 resize-none outline-none leading-relaxed py-1 min-h-[2.5rem] overflow-hidden"
              value={block.text}
              placeholder="Start writing..."
              onChange={(e) => {
                updateBlockText(block.id, e.target.value);
                autoResizeTextarea(e);
              }}
              onKeyDown={(e) => handleKeyDown(e, index)}
              rows={1}
            />
          </div>
        ))}

        {/* Empty State click catcher */}
        {entry.blocks.length === 0 && (
          <div 
            className="h-32 flex items-center justify-center text-gray-600 cursor-text"
            onClick={() => addBlock()}
          >
            Click to start writing your day...
          </div>
        )}
      </div>
    </div>
  );
};

export default DailyEditor;

import React, { useState } from 'react';
import { ChevronUp, ChevronDown, Check, X, Maximize2, Minimize2, Plus } from 'lucide-react';
import { TodoItem } from '../types';

interface BottomPanelProps {
  todos: TodoItem[];
  setTodos: React.Dispatch<React.SetStateAction<TodoItem[]>>;
}

export const BottomPanel: React.FC<BottomPanelProps> = ({ todos, setTodos }) => {
  const [expanded, setExpanded] = useState(false);
  const [newTodo, setNewTodo] = useState('');

  const addTodo = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTodo.trim()) return;
    const item: TodoItem = {
      id: Date.now().toString(),
      text: newTodo,
      completed: false
    };
    setTodos([...todos, item]);
    setNewTodo('');
  };

  const toggleTodo = (id: string) => {
    setTodos(todos.map(t => t.id === id ? { ...t, completed: !t.completed } : t));
  };

  const removeTodo = (id: string) => {
    setTodos(todos.filter(t => t.id !== id));
  };

  // Clear completed button logic
  const clearCompleted = () => {
    setTodos(todos.filter(t => !t.completed));
  };

  return (
    <div 
      className={`fixed bottom-0 left-0 right-0 bg-journal-800 border-t border-journal-600 shadow-2xl transition-all duration-300 z-50
        ${expanded ? 'h-96' : 'h-10'}
      `}
      style={{ marginLeft: 'var(--sidebar-width, 64px)', marginRight: 'var(--right-panel-width, 40px)' }}
    >
      {/* Header Toggle */}
      <div 
        className="h-10 flex items-center justify-between px-4 cursor-pointer hover:bg-journal-700 bg-journal-900"
        onClick={() => setExpanded(!expanded)}
      >
        <span className="font-semibold text-sm text-gray-300">Tasks ({todos.filter(t => !t.completed).length})</span>
        {expanded ? <ChevronDown size={16} /> : <ChevronUp size={16} />}
      </div>

      {/* Content */}
      <div className="p-4 h-[calc(100%-40px)] flex flex-col">
        <form onSubmit={addTodo} className="flex mb-4">
          <input 
            type="text" 
            value={newTodo}
            onChange={(e) => setNewTodo(e.target.value)}
            placeholder="Add a new task..."
            className="flex-1 bg-journal-900 border border-journal-600 rounded-l px-3 py-2 text-white outline-none focus:border-journal-accent"
          />
          <button type="submit" className="bg-journal-accent text-journal-900 px-4 py-2 rounded-r font-bold hover:opacity-90">
            <Plus size={18} />
          </button>
        </form>

        <div className="flex-1 overflow-y-auto space-y-2">
          {todos.map(todo => (
            <div key={todo.id} className="flex items-center group bg-journal-900 p-2 rounded border border-journal-600/50">
              <button 
                onClick={(e) => { e.stopPropagation(); toggleTodo(todo.id); }}
                className={`w-5 h-5 rounded border flex items-center justify-center mr-3 transition-colors
                  ${todo.completed ? 'bg-journal-accent border-journal-accent' : 'border-gray-500 hover:border-journal-accent'}
                `}
              >
                {todo.completed && <Check size={14} className="text-black" />}
              </button>
              <span className={`flex-1 text-sm ${todo.completed ? 'line-through text-gray-500' : 'text-gray-200'}`}>
                {todo.text}
              </span>
              <button 
                onClick={(e) => { e.stopPropagation(); removeTodo(todo.id); }}
                className="opacity-0 group-hover:opacity-100 text-gray-500 hover:text-red-400 p-1"
              >
                <X size={16} />
              </button>
            </div>
          ))}
        </div>

        {todos.some(t => t.completed) && (
            <button onClick={clearCompleted} className="text-xs text-gray-500 hover:text-white mt-2 self-end">
                Clear Completed
            </button>
        )}
      </div>
    </div>
  );
};

